allow:
Bash(powershell.exe -Command "
Add-Type @'
using System;
using System.Runtime.InteropServices;
public class Win32 {
    [DllImport\(\\"user32.dll\\"\)] public static extern bool SetForegroundWindow\(IntPtr hWnd\);
    [DllImport\(\\"user32.dll\\"\)] public static extern bool ShowWindow\(IntPtr hWnd, int nCmdShow\);
}
'@
\\$proc = Get-Process -Name 'PSIM' -ErrorAction SilentlyContinue | Select-Object -First 1
if \(\\$proc\) {
    [Win32]::ShowWindow\(\\$proc.MainWindowHandle, 9\)  # SW_RESTORE
    [Win32]::SetForegroundWindow\(\\$proc.MainWindowHandle\)
    Write-Output 'PSIM window brought to front'
} else {
    Write-Output 'PSIM not found'
}
" 2>&1)
